patch:
diff --git a/llvm/lib/Transforms/IPO/FunctionAttrs.cpp b/llvm/lib/Transforms/IPO/FunctionAttrs.cpp
index f918d7e059b6..53b0167736f5 100644
--- a/llvm/lib/Transforms/IPO/FunctionAttrs.cpp
+++ b/llvm/lib/Transforms/IPO/FunctionAttrs.cpp
@@ -65,6 +65,7 @@
 #include <map>
 #include <optional>
 #include <vector>
+#include <climits>

 using namespace llvm;

@@ -677,9 +678,15 @@ ArgumentAccessInfo getArgumentAccessInfo(const Instruction *I,
     auto *ConstantLength = dyn_cast<ConstantInt>(Length);
     if (ConstantLength && Offset &&
         ConstantLength->getValue().isStrictlyPositive()) {
+      int64_t OffsetVal = *Offset;
+      int64_t LengthVal = ConstantLength->getSExtValue();
+      // Check for signed overflow when adding Offset and Length.
+      if (OffsetVal > 0 && LengthVal > INT64_MAX - OffsetVal)
+        return std::nullopt;
+      // No overflow, create the range.
       return ConstantRange(
-          APInt(64, *Offset, true),
-          APInt(64, *Offset + ConstantLength->getSExtValue(), true));
+          APInt(64, OffsetVal, true),
+          APInt(64, OffsetVal + LengthVal, true));
     }
     return std::nullopt;
   };

